class Solution {
    public int countBinarySubstrings(String s) {
        int count = 0;
        int prev = 0, curr = 1;
        for (int i = 1; i < s.length(); i++) {
            if (s.charAt(i) == s.charAt(i - 1)) {
                curr++;
            } else {
                count += Math.min(prev, curr);
                prev = curr;
                curr = 1;
            }
        }
        return count + Math.min(prev, curr);
    }
}
```

